import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.DEqXEGcv.js";const u=JSON.parse('{"title":"NAS Image Installation","description":"","frontmatter":{},"headers":[],"relativePath":"en/docs/guide/nas.md","filePath":"en/docs/guide/nas.md"}'),r={name:"en/docs/guide/nas.md"};function i(s,e,l,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="nas-image-installation" tabindex="-1">NAS Image Installation <a class="header-anchor" href="#nas-image-installation" aria-label="Permalink to &quot;NAS Image Installation&quot;">​</a></h1><p>RDE provides an ISO image built on <strong>Debian 13</strong> that turns any x86_64 machine into a full-featured NAS + cloud desktop.</p><h2 id="comparison-with-curl-deb-deployment" tabindex="-1">Comparison with curl/deb Deployment <a class="header-anchor" href="#comparison-with-curl-deb-deployment" aria-label="Permalink to &quot;Comparison with curl/deb Deployment&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>curl / deb Install</th><th>NAS ISO Image</th></tr></thead><tbody><tr><td><strong>Base System</strong></td><td>Requires existing Ubuntu / Debian</td><td>Includes complete Debian 13 system</td></tr><tr><td><strong>Dependencies</strong></td><td>Some installed via network</td><td>All pre-installed, ready to use</td></tr><tr><td><strong>Flatpak</strong></td><td>First run requires setup for dependencies</td><td>Pre-installed, no extra setup needed</td></tr><tr><td><strong>Use Case</strong></td><td>Existing cloud server / VPS</td><td>Fresh hardware / repurposed PC as NAS</td></tr><tr><td><strong>Install Method</strong></td><td>One-line command</td><td>USB drive boot installation</td></tr></tbody></table><h2 id="download" tabindex="-1">Download <a class="header-anchor" href="#download" aria-label="Permalink to &quot;Download&quot;">​</a></h2><p>Available on GitHub Releases.</p><h2 id="system-requirements" tabindex="-1">System Requirements <a class="header-anchor" href="#system-requirements" aria-label="Permalink to &quot;System Requirements&quot;">​</a></h2><ul><li><strong>CPU</strong>: x86_64 architecture (Intel / AMD)</li><li><strong>RAM</strong>: Minimum 2 GB, recommended 4 GB+</li><li><strong>Disk</strong>: Minimum 16 GB, recommended 64 GB+ SSD</li><li><strong>Network</strong>: Wired network connection</li></ul><h2 id="installation-steps" tabindex="-1">Installation Steps <a class="header-anchor" href="#installation-steps" aria-label="Permalink to &quot;Installation Steps&quot;">​</a></h2><h3 id="_1-create-bootable-usb-drive" tabindex="-1">1. Create Bootable USB Drive <a class="header-anchor" href="#_1-create-bootable-usb-drive" aria-label="Permalink to &quot;1. Create Bootable USB Drive&quot;">​</a></h3><p>Prepare a USB drive of 4 GB or larger and write the ISO using:</p><p><strong>Windows:</strong></p><ul><li>Rufus — Select ISO file, partition type GPT, click Start</li><li>Ventoy — Install Ventoy, then simply copy the ISO to the USB drive</li></ul><p><strong>Linux / macOS:</strong></p><pre><code># Find USB drive device name (e.g., /dev/sdb)
lsblk
# Write ISO (replace device name — this will erase all data on the drive)
sudo dd if=rde-os.iso of=/dev/sdX bs=4M status=progress &amp;&amp; sync
</code></pre><h3 id="_2-bios-setup" tabindex="-1">2. BIOS Setup <a class="header-anchor" href="#_2-bios-setup" aria-label="Permalink to &quot;2. BIOS Setup&quot;">​</a></h3><ol><li>Insert USB drive, press F2 / F12 / Del at boot to enter BIOS</li><li>Set USB drive as the first boot device</li><li>Save and exit, auto-boot from USB drive</li></ol><h3 id="_3-install-system" tabindex="-1">3. Install System <a class="header-anchor" href="#_3-install-system" aria-label="Permalink to &quot;3. Install System&quot;">​</a></h3><p>Follow the Debian installation wizard to complete the system setup. After reboot, the RDE desktop starts automatically.</p><h3 id="_4-access-desktop" tabindex="-1">4. Access Desktop <a class="header-anchor" href="#_4-access-desktop" aria-label="Permalink to &quot;4. Access Desktop&quot;">​</a></h3><p>Open a browser and navigate to <code>http://&lt;NAS_IP&gt;:3080</code> to enter the RDE desktop.</p><h2 id="pre-installed-content" tabindex="-1">Pre-installed Content <a class="header-anchor" href="#pre-installed-content" aria-label="Permalink to &quot;Pre-installed Content&quot;">​</a></h2><p>The ISO image includes these extras compared to curl deployment:</p><ul><li><strong>Flatpak Runtime</strong>: Install Flatpak apps directly, no setup needed</li><li><strong>Complete System Dependencies</strong>: All system libraries and tools required by RDE</li><li><strong>Disk Management Tools</strong>: Convenient for managing multiple drives in NAS scenarios</li><li><strong>Network Configuration Tools</strong>: Static IP, bridges, and other common NAS network settings</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="how-to-update-rde-after-iso-installation" tabindex="-1">How to update RDE after ISO installation? <a class="header-anchor" href="#how-to-update-rde-after-iso-installation" aria-label="Permalink to &quot;How to update RDE after ISO installation?&quot;">​</a></h3><p>ISO-installed RDE can be updated via deb package:</p><pre><code>wget https://github.com/ruizi-store/rde/releases/latest/download/rde_latest_amd64.deb &amp;&amp; sudo apt install -y ./rde_latest_amd64.deb
</code></pre><h3 id="can-i-try-it-in-a-virtual-machine" tabindex="-1">Can I try it in a virtual machine? <a class="header-anchor" href="#can-i-try-it-in-a-virtual-machine" aria-label="Permalink to &quot;Can I try it in a virtual machine?&quot;">​</a></h3><p>Yes. Create a VM in VMware / VirtualBox / Proxmox, mount the ISO and install. Recommended: 2 cores, 4 GB RAM.</p><h3 id="how-does-it-compare-to-synology-fnos" tabindex="-1">How does it compare to Synology / fnOS? <a class="header-anchor" href="#how-does-it-compare-to-synology-fnos" aria-label="Permalink to &quot;How does it compare to Synology / fnOS?&quot;">​</a></h3><p>RDE is an open-source web desktop solution that runs on any x86 hardware. Compared to Synology and fnOS:</p><ul><li>Fully open source, no licensing restrictions</li><li>Built-in Docker app store</li><li>Web desktop experience, not just a NAS management interface</li></ul>`,33)])])}const m=t(r,[["render",i]]);export{u as __pageData,m as default};
